CREATE TABLE IF NOT EXISTS revenue_location_master (
    id BIGSERIAL PRIMARY KEY,
    idn VARCHAR(50),
    lgd_district_code VARCHAR(20),
    dist_name_eng VARCHAR(255),
    lgd_subdiv_code VARCHAR(20),
    subdiv_name_eng VARCHAR(255),
    lgd_circle_code VARCHAR(20),
    rsname_eng VARCHAR(255),
    lgd_tehsil_code VARCHAR(20),
    tname_eng VARCHAR(255),
    lgd_village_code VARCHAR(20),
    mouname_eng VARCHAR(255)
);

CREATE INDEX IF NOT EXISTS idx_revenue_location_master_district
    ON revenue_location_master (lgd_district_code);

CREATE INDEX IF NOT EXISTS idx_revenue_location_master_subdivision
    ON revenue_location_master (lgd_subdiv_code);

CREATE INDEX IF NOT EXISTS idx_revenue_location_master_circle
    ON revenue_location_master (lgd_circle_code);

CREATE INDEX IF NOT EXISTS idx_revenue_location_master_tehsil
    ON revenue_location_master (lgd_tehsil_code);

